import graphene
from flask import Flask, request

# Define a GraphQL type for product catalog data
class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category = graphene.String()
    reviews = graphene.List(Review)

class Review(graphene.ObjectType):
    id = graphene.ID()
    text = graphene.String()
    rating = graphene.Int()

# Define a GraphQL query for products
class Query:
    product = graphene.Field(Product, id=graphene.ID())
    products = graphene.List(Product)

    def resolve_product(parent, info, id):
        return Product(id=id, name="Example Product", description="This is an example product.", price=10.99, category="Category 1")

    def resolve_products(parent, info):
        return [Product(id="1", name="Product 1", description="This is product 1.", price=10.99, category="Category 1"), Product(id="2", name="Product 2", description="This is product 2.", price=15.99, category="Category 2")]

# Define a GraphQL query for categories
class Category:
    id = graphene.ID()
    name = graphene.String()
    products = graphene.List(Product)

    def resolve_category(parent, info, id):
        return Category(id=id, name="Example Category", products=[Product(id="1", name="Product 1", description="This is product 1.", price=10.99, category="Category 1"), Product(id="2", name="Product 2", description="This is product 2.", price=15.99, category="Category 2")])

# Define a GraphQL query for user reviews
class Review:
    id = graphene.ID()
    text = graphene.String()
    rating = graphene.Int()

    def resolve_review(parent, info, id):
        return Review(id=id, text="This is an example review.", rating=5)

# Define a Flask app
app = Flask(__name__)

# Register the GraphQL schema with the app
schema = graphene.Schema(query=Query, types=[Product, Category, Review])

@app.route("/graphql", methods=["POST"])
def graphql_server():
    data = request.get_json()
    result = schema.execute(data)
    return jsonify(result.data)